import{_ as i,o as t,c as o,aw as a}from"./chunks/framework.DLufY-ao.js";const _=JSON.parse('{"title":"Значение свойств","description":"","frontmatter":{},"headers":[],"relativePath":"wiki/dev-commit/layout/css/properties/properties-value.md","filePath":"wiki/dev-commit/layout/css/properties/properties-value.md"}'),n={name:"wiki/dev-commit/layout/css/properties/properties-value.md"};function r(l,e,s,c,d,u){return t(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="значение-своиств" tabindex="-1">Значение свойств <a class="header-anchor" href="#значение-своиств" aria-label="Permalink to &quot;Значение свойств&quot;">​</a></h1><h2 id="значения-none-unset-inherit-initial" tabindex="-1">Значения: <code>none</code>, <code>unset</code>, <code>inherit</code>, <code>initial</code> <a class="header-anchor" href="#значения-none-unset-inherit-initial" aria-label="Permalink to &quot;Значения: `none`, `unset`, `inherit`, `initial`&quot;">​</a></h2><ul><li><code>none</code> - Отменяет заданные значения для свойства</li><li><code>unset</code> - Комбинация ключевых слов <u>initial</u> и <u>inherit</u>. Ключевое слово <u>unset</u> устанавливает значение свойства как <u>inherit</u>, если свойство наследуется от своего родителя, в противном случае значение устанавливается как <u>initial</u></li><li><code>inherit</code> - Сообщает, что необходимо наследовать значение свойства у родительского элемента. Результат будет заметен только в том случае, если у родителя указанное свойство установлено</li><li><code>initial</code> - Применяется для установки исходного значения свойства. Может пригодиться в нескольких случаях, к примеру, восстановить значения свойств, заданных браузером по умолчанию или задать начальное значение свойства, измененное в результате наследования</li></ul>',3)])])}const h=i(n,[["render",r]]);export{_ as __pageData,h as default};
